    /// Extract i128 from [u64; 8] array (embedded profile: 19 decimals)
    /// Takes the first 2 u64s (16 bytes = 128 bits) from the array
    #[inline]
    pub fn extract_i128_from_u64_8(arr: [u64; 8]) -> i128 {
        let low = arr[0] as i128;
        let high = arr[1] as i128;
        low | (high << 64)
    }

    /// Extract [u64; 4] from [u64; 8] array (balanced profile: 38 decimals)
    /// Takes the first 4 u64s (32 bytes = 256 bits) from the array
    #[inline]
    pub fn extract_u64_4_from_u64_8(arr: [u64; 8]) -> [u64; 4] {
        [arr[0], arr[1], arr[2], arr[3]]
    }
